/* knob-asset.js — Pre-rendered 54x6912 knob strip PNGs (128 frames of 54x54) */
/* Three styles: gray (default), green, ice. Generated offline. */

var KNOB_STYLES = {
  gray: "",
  green: "",
  ice: ""
};

function getKnobPngBytes(style) {
  style = style || "gray";
  var b64 = KNOB_STYLES[style] || KNOB_STYLES.gray;
  var binary = atob(b64);
  var bytes = new Uint8Array(binary.length);
  for (var i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes;
}
